import React from 'react';
import styles from './HomePage.module.css';

const HomePage = () => {
  return (
    <div className={styles.homeContainer}>
      <header className={styles.header}>
        <h1>Welcome to the Admin Dashboard</h1>
        <p>Manage and oversee all platform operations effortlessly.</p>
      </header>
      
      <section className={styles.content}>
        <div className={styles.imageSection}>
          <img 
            src="https://via.placeholder.com/300" 
            alt="Admin Overview" 
            className={styles.contentImage}
          />
          <p>Track performance and access essential insights in real-time.</p>
        </div>
        
        <div className={styles.imageSection}>
          <img 
            src="https://via.placeholder.com/300" 
            alt="Manage Resources" 
            className={styles.contentImage}
          />
          <p>Organize resources, monitor data, and streamline tasks efficiently.</p>
        </div>
        
        <div className={styles.authButtons}>
          <button className={styles.loginBtn}>Login</button>
          <button className={styles.signupBtn}>Sign Up</button>
        </div>
      </section>
    </div>
  );
};

export default HomePage;
